        __w7 = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(56));
    }

    /// <summary>Creates a new UnalignedFrame512 by reading <see cref="SIZE_IN_BYTES"/> bytes from a little-endian byte span.</summary>
    /// <param name="bytes">The source span. Must contain at least <see cref="SIZE_IN_BYTES"/> bytes.</param>
    /// <returns>The deserialized UnalignedFrame512.</returns>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static UnalignedFrame512 ReadFrom(ReadOnlySpan<byte> bytes) => new(bytes);

    /// <summary>Writes the value as little-endian bytes into the destination span.</summary>
    /// <param name="destination">The destination span. Must contain at least <see cref="SIZE_IN_BYTES"/> bytes.</param>
    /// <exception cref="ArgumentException">The span is too short.</exception>
    public void WriteTo(Span<byte> destination)
    {
        if (destination.Length < SIZE_IN_BYTES)
            throw new ArgumentException($"Span must contain at least {SIZE_IN_BYTES} bytes.", nameof(destination));
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(0), __w0);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(8), __w1);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(16), __w2);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(24), __w3);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(32), __w4);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(40), __w5);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(48), __w6);
        BinaryPrimitives.WriteUInt64LittleEndian(destination.Slice(56), __w7);
    }

    /// <summary>Attempts to write the value as little-endian bytes into the destination span.</summary>
    /// <param name="destination">The destination span.</param>
    /// <param name="bytesWritten">The number of bytes written on success.</param>
    /// <returns>true if the destination span was large enough; otherwise, false.</returns>
    public bool TryWriteTo(Span<byte> destination, out int bytesWritten)
    {
        if (destination.Length < SIZE_IN_BYTES)
        {
            bytesWritten = 0;
            return false;
        }
        WriteTo(destination);
        bytesWritten = SIZE_IN_BYTES;
        return true;
    }

    /// <summary>Returns the value as a new little-endian byte array.</summary>
    /// <returns>A byte array of length <see cref="SIZE_IN_BYTES"/>.</returns>
    public byte[] ToByteArray()
    {
        var bytes = new byte[SIZE_IN_BYTES];
        WriteTo(bytes);
        return bytes;
    }

    private static bool IsHexPrefix(ReadOnlySpan<char> s) => s.Length >= 2 && s[0] == '0' && (s[1] == 'x' || s[1] == 'X');
    private static bool IsBinaryPrefix(ReadOnlySpan<char> s) => s.Length >= 2 && s[0] == '0' && (s[1] == 'b' || s[1] == 'B');

    private static string RemoveUnderscores(ReadOnlySpan<char> s)
    {
        bool hasUnderscore = false;
        foreach (var c in s) { if (c == '_') { hasUnderscore = true; break; } }
        if (!hasUnderscore) return s.ToString();
        var sb = new System.Text.StringBuilder(s.Length);
        foreach (var c in s) { if (c != '_') sb.Append(c); }
        return sb.ToString();
    }

    /// <summary>Parses a string into a UnalignedFrame512. Supports decimal, hex (0x prefix), and binary (0b prefix) formats with optional underscores.</summary>
    public static UnalignedFrame512 Parse(string s, IFormatProvider? provider)
    {
        ArgumentNullException.ThrowIfNull(s);
        var span = s.AsSpan();
        if (IsBinaryPrefix(span))
        {
            BigInteger val = 0;
            foreach (var c in RemoveUnderscores(span.Slice(2)))
                val = (val << 1) | (c == '1' ? 1 : 0);
            return FromBigInteger(val);
        }
        if (IsHexPrefix(span))
            return FromBigInteger(BigInteger.Parse("0" + RemoveUnderscores(span.Slice(2)), NumberStyles.HexNumber, provider));
        return FromBigInteger(BigInteger.Parse(RemoveUnderscores(span), NumberStyles.Integer, provider));
    }

    /// <summary>Tries to parse a string into a UnalignedFrame512.</summary>
    public static bool TryParse(string? s, IFormatProvider? provider, out UnalignedFrame512 result)
    {
        if (s is null) { result = default; return false; }
        try { result = Parse(s, provider); return true; }
        catch { result = default; return false; }
    }

    /// <summary>Parses a span of characters into a UnalignedFrame512.</summary>
    public static UnalignedFrame512 Parse(ReadOnlySpan<char> s, IFormatProvider? provider) => Parse(s.ToString(), provider);

    /// <summary>Tries to parse a span of characters into a UnalignedFrame512.</summary>
    public static bool TryParse(ReadOnlySpan<char> s, IFormatProvider? provider, out UnalignedFrame512 result) => TryParse(s.ToString(), provider, out result);

    /// <summary>Parses a string using invariant culture.</summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static UnalignedFrame512 Parse(string s) => Parse(s, CultureInfo.InvariantCulture);

    /// <summary>Tries to parse a string using invariant culture.</summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static bool TryParse(string? s, out UnalignedFrame512 result) => TryParse(s, CultureInfo.InvariantCulture, out result);

    /// <summary>Formats the value using the specified format and format provider.</summary>
    public string ToString(string? format, IFormatProvider? formatProvider) => ToBigInteger().ToString(format, formatProvider);

    /// <summary>Tries to format the value into the provided span of characters.</summary>
    public bool TryFormat(Span<char> destination, out int charsWritten, ReadOnlySpan<char> format, IFormatProvider? provider)
    {
        var str = ToString(format.ToString(), provider);
        if (str.Length <= destination.Length)
        {
            str.AsSpan().CopyTo(destination);
            charsWritten = str.Length;
            return true;
        }
        charsWritten = 0;
        return false;
    }

    /// <summary>Compares this instance to a specified object.</summary>
    public int CompareTo(object? obj)
    {
        if (obj is null) return 1;
        if (obj is UnalignedFrame512 other) return CompareTo(other);
        throw new ArgumentException("Object must be of type UnalignedFrame512", nameof(obj));
    }

    /// <summary>Compares this instance to another UnalignedFrame512.</summary>
    public int CompareTo(UnalignedFrame512 other)
    {
        if (__w7 != other.__w7) return __w7.CompareTo(other.__w7);
        if (__w6 != other.__w6) return __w6.CompareTo(other.__w6);
        if (__w5 != other.__w5) return __w5.CompareTo(other.__w5);
        if (__w4 != other.__w4) return __w4.CompareTo(other.__w4);
        if (__w3 != other.__w3) return __w3.CompareTo(other.__w3);
        if (__w2 != other.__w2) return __w2.CompareTo(other.__w2);
        if (__w1 != other.__w1) return __w1.CompareTo(other.__w1);
        if (__w0 != other.__w0) return __w0.CompareTo(other.__w0);
        return 0;
    }

    /// <summary>Indicates whether this instance is equal to another UnalignedFrame512.</summary>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public bool Equals(UnalignedFrame512 other) => this == other;

    /// <summary>JSON converter that serializes UnalignedFrame512 as a hex string.</summary>
    private sealed class UnalignedFrame512JsonConverter : JsonConverter<UnalignedFrame512>
    {
        /// <summary>Reads a UnalignedFrame512 from a JSON string.</summary>
        public override UnalignedFrame512 Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var s = reader.GetString();
            return s is null ? default : UnalignedFrame512.Parse(s);
        }

        /// <summary>Writes a UnalignedFrame512 to JSON as a hex string.</summary>
        public override void Write(Utf8JsonWriter writer, UnalignedFrame512 value, JsonSerializerOptions options)
        {
            writer.WriteStringValue(value.ToString());
        }
    }

